  nom_complet: fields.nom_complet || fields.nom_utilisateur || 'Utilisateur'
}}];

function buildNav(userName, userRole, token, baseUrl, currentPage) {
  const ADMIN = ['commercial','responsable','patron','webmaster'];
  const isAdmin = ADMIN.includes(userRole);
  const roleNames = { decoupe_toile:'Découpe toile', couture:'Couture', decoupe_armature:'Découpe armature', assemblage:'Assemblage', reglage:'Réglage', emballage:'Emballage', expedition:'Expédition', commercial:'Commercial', responsable:'Responsable', patron:'Patron', webmaster:'Webmaster' };
  const roleDisplay = roleNames[userRole] || userRole;
  const u = (p) => `https://${baseUrl}/webhook/${p}?token=${token}`;
  const a = (page) => currentPage === page ? ' active' : '';
  const links = [];
  links.push({ label:'Accueil', page:'home', href:u('home') });
  links.push({ label:'Production', page:'production', href:u('production') });
  if (isAdmin) links.push({ label:'Validation', page:'validation', href:u('validation') });
  if (isAdmin || userRole==='expedition') links.push({ label:'Dashboard', page:'dashboard', href:u('dashboard') });
  if (['expedition','responsable','patron','webmaster'].includes(userRole)) links.push({ label:'Expédition', page:'expedition', href:u('expedition') });
  if (isAdmin) links.push({ label:'Import', page:'upload', href:u('upload') });
  if (['responsable','patron','webmaster'].includes(userRole)) links.push({ label:'Compta', page:'comptabilite', href:u('comptabilite') });
  if (userRole==='webmaster') links.push({ label:'Utilisateurs', page:'users', href:u('users') });
  const linksHtml = links.map(l => `<a href="${l.href}" class="nav-link${a(l.page)}">${l.label}</a>`).join('');
  return `<nav class="main-nav">
    <a class="nav-brand" href="${u('home')}">MON USINE</a>
    <div class="nav-links">${linksHtml}</div>
    <div class="nav-user">
      <span class="nav-uname">${userName}</span>
      <span class="nav-urole">${roleDisplay}</span>
      <a class="nav-logout" href="https://${baseUrl}/webhook/login">Déconnexion</a>
    </div>
  </nav>`;
}

