<script>
var dz=document.getElementById('dz'),fi=document.getElementById('fi'),finfo=document.getElementById('finfo'),fname=document.getElementById('fname'),fsize=document.getElementById('fsize'),sbtn=document.getElementById('sbtn');
dz.onclick=function(){fi.click()};
fi.onchange=function(){if(!fi.files.length)return;var n=fi.files.length,t=0;for(var k=0;k<n;k++)t+=fi.files[k].size;fname.textContent=n===1?fi.files[0].name:n+' fichiers PDF';fsize.textContent=(t/1024/1024).toFixed(2)+' MB';finfo.className='file-info show';sbtn.className='submit-btn ready';sbtn.textContent='Envoyer '+n+' fichier'+(n>1?'s':'');dz.className='drop-zone has-file'};
['dragenter','dragover'].forEach(function(e){dz.addEventListener(e,function(ev){ev.preventDefault();dz.classList.add('drag')})});
['dragleave','drop'].forEach(function(e){dz.addEventListener(e,function(ev){ev.preventDefault();dz.classList.remove('drag')})});
dz.addEventListener('drop',function(ev){var fs=ev.dataTransfer.files,ps=[];for(var k=0;k<fs.length;k++){if(fs[k].name.toLowerCase().endsWith('.pdf'))ps.push(fs[k])}if(ps.length){var dt=new DataTransfer();for(var k=0;k<ps.length;k++)dt.items.add(ps[k]);fi.files=dt.files;fi.dispatchEvent(new Event('change'))}});
document.getElementById('form').onsubmit=function(e){
if(!fi.files.length){e.preventDefault();return false}
if(fi.files.length===1){document.getElementById('load').className='loading show';sbtn.style.pointerEvents='none';return true}
e.preventDefault();
var ld=document.getElementById('load'),pr=ld.querySelector('p');ld.className='loading show';sbtn.style.pointerEvents='none';
var url=document.getElementById('form').action,tot=fi.files.length,ok=0,er=[],ix=0;
