x.send(fd)}
function end(){
var hu=document.getElementById('hurl')?document.getElementById('hurl').value:'';
var ic,ti,ms,cl;
if(ok===tot){ic='\u2705';cl='#059669';ti=ok+' fichier'+(ok>1?'s':'')+' import\u00e9'+(ok>1?'s':'');ms='Le traitement d\u00e9marrera dans les prochaines minutes.'}
else if(ok>0){ic='\u26a0\ufe0f';cl='#d97706';ti=ok+'/'+tot+' import\u00e9'+(ok>1?'s':'');ms='Erreur : '+er.join(', ')}
else{ic='\u274c';cl='#dc2626';ti='\u00c9chec';ms='Aucun fichier import\u00e9.'}
ld.innerHTML='<div style="font-size:4rem;margin-bottom:20px">'+ic+'</div><div style="background:#fff;padding:30px 40px;border-radius:14px;text-align:center;max-width:500px;margin:0 20px"><h2 style="color:'+cl+';margin-bottom:12px;font-size:1.5rem">'+ti+'</h2><p style="color:#6b7280;margin-bottom:24px;line-height:1.5">'+ms+'</p><div style="display:flex;gap:12px;justify-content:center;flex-wrap:wrap"><a href="javascript:location.reload()" style="display:inline-block;padding:12px 24px;border-radius:12px;text-decoration:none;font-weight:600;background:#059669;color:#fff">Nouvel import</a>'+(hu?'<a href="'+hu+'" style="display:inline-block;padding:12px 24px;border-radius:12px;text-decoration:none;font-weight:600;background:#eff6ff;border:1px solid #bfdbfe;color:#2563eb">Accueil</a>':'')+'</div></div>'}
go()};
</script>
</body>
